#include <iostream>
#include <vector>
#include <string>

class TweetCounts {
public:
    TweetCounts() {}

    void recordTweet(std::string tweetName, int time) {
        tweets[tweetName][time]++;
    }

    vector<int> getTweetCountsPerFrequency(std::string freq, std::string tweetName, int startTime, int endTime) {
        vector<int> countsPerFrequency;
        for (int i = startTime; i < endTime; i += freq) {
            countsPerFrequency.push_back(tweets[tweetName][i];
        }
        return countsPerFrequency;
    }

private:
    std::map<std::string, std::map<int, int> tweets;
};
```

